    /**
     * Personal Information save in database and Validation
     */
    async submitPersonalInfo() {
        const { first_name, last_name, email, country, city, description } = this.state.personalInfo;
        let { firstNameError, lastNameError, emailError, countryError, cityError, personalInfoError } = '';
        if (!first_name) {
            firstNameError = "This field is required";
        }
        if (!last_name) {
            lastNameError = "This field is required";
        }
        if (!email) {
            emailError = "This field is required";
        }
        if (!country) {
            countryError = "This field is required";
        }
        if (!city) {
            cityError = "This field is required";
        }
        if (!description) {
            personalInfoError = "This field is required";
        }
        this.setState(prevState => ({
            personalInfo: {
                ...prevState.personalInfo,
                error: {
                    ...prevState.personalInfo.error,
                    firstNameError: firstNameError,
                    lastNameError: lastNameError,
                    emailError: emailError,
                    countryError: countryError,
                    personalInfoError: personalInfoError

                }
            }
        })
        )
        if (firstNameError || lastNameError || emailError || countryError || personalInfoError) {
            return true;
        }
        this.setState({ loading: true });
        let data = {
            first_name: first_name,
            last_name: last_name,
            email: email,
            country: country,
            city: city,
            description: description,
        }
        const response = await ApiRequest.postRequest('/mentorPersonalInfo', data)
        if (response !== undefined && response.status === 200 && response.status !== 422) {
            this.tabActiveByClassName('step_two');
            // toastAlert('success', response.data.success);
        } else if (response !== undefined && response.status === 404) {
            // toastAlert('warn', response.data.success);
        } else {
            toastAlert('error', "Something went wrong please try again!");
        }

    }



