    workExpCardDelete = (event) => {
        let prevHtml = this.state.workExpert.htmlCard;
        let allWorkExp = this.state.workExpert.allExp;
        let index = prevHtml.findIndex(x => x.key == event.currentTarget.getAttribute('data-title'));
        if (index !== -1) {
            prevHtml.splice(index, 1);
            this.setState(prevState => ({
                workExpert: {
                    ...prevState.workExpert,
                    htmlCard: prevHtml
                }
            }))
        }
        index = allWorkExp.findIndex(x => x.session_title == event.currentTarget.getAttribute('data-title'));
        if (index !== -1) {
            allWorkExp.splice(index, 1);
            this.setState(prevState => ({
                ...prevState.workExpert,
                allExp: allWorkExp
            }))
            // toastAlert('success', 'Work Expertise successfully deleted');
        }
    }
    addWorkExpCard() {
        const { session_title, session_type, session_duration, session_price } = this.state.workExpert;
        let { sessionTitleError, sessionTypeError, sessionDurationError, sessionPriceError } = '';
        let allWorkExp = this.state.workExpert.allExp
        let arr = {
            session_title: this.state.workExpert.session_title,
            session_type: this.state.workExpert.session_type,
            session_price: this.state.workExpert.session_price,
            session_duration: this.state.workExpert.session_duration,
        }
        // Validation
        if (!session_title) {
            sessionTitleError = 'This field is required.';
        }
        if (!session_type) {
            sessionTypeError = 'This field is required.';
        }
        if (!session_price) {
            sessionPriceError = 'This field is required.';
        }
        this.setState(prevState => ({
            workExpert: {
                ...prevState.workExpert,
                error: {
                    ...prevState.workExpert.error,
                    sessionTitleError: sessionTitleError,
                    sessionTypeError: sessionTypeError,
                    sessionPriceError: sessionPriceError,

                }
            }
        })
        )
        if (sessionTitleError || sessionTypeError || sessionPriceError) {
            return true;
        }
        // End Validation

        if (allWorkExp.length == 0) {
            allWorkExp.push(arr);
        } else {
            let index = allWorkExp.findIndex(x => x.session_title == this.state.workExpert.session_title);
            if (index === -1) {
                allWorkExp.push(arr);
            } else {
                allWorkExp[index] = arr;
            }
        }


        // Insert card
        let html = this.workExpCardHtml();
        let prevHtml = this.state.workExpert.htmlCard;
        if (prevHtml.length == 0) {
            prevHtml.push(html);
        } else {
            let index = prevHtml.findIndex(x => x.key == this.state.workExpert.session_title);
            if (index === -1) {
                prevHtml.push(html);
            } else {
                prevHtml[index] = html;
            }
        }
        this.setState(prevState => ({
            workExpert: {
                ...prevState.workExpert,
                allExp: allWorkExp,
                htmlCard: prevHtml
            }
        }))
    }
    /**
     * Help to make a Work Experience array from already saved data
     * @param  {object} data
     */
    makeWorkExpArray = (data) => {
        let allWorkExp = this.state.workExpert.allExp;
        data.expertise_details.map(el => {
            let arr = {
                session_title: el.session_title,
                session_type: el.session_type,
                session_price: el.session_price,
                session_duration: el.session_duration,
            }
            if (arr.session_title && arr.session_type) {
                if (allWorkExp.length == 0) {
                    allWorkExp.push(arr);
                } else {
                    let index = allWorkExp.findIndex(x => x.session_title == this.state.workExpert.session_title);
                    if (index === -1) {
                        allWorkExp.push(arr);
                    } else {
                        allWorkExp[index] = arr;
                    }
                }
            }
        })
        this.setState(prevState => ({
            workExpert: {
                ...prevState.workExpert,
                allExp: allWorkExp
            }
        }))
    }
