    addTimeSlot = (el) => {
        if (this.state.timeSlots[el]) {
            const arr = [];
            this.state.timeSlots[el].map((element, index) => {
                const val = this.newTimeSlot(element, index);
                arr.push(val);
            })
            this.setState(prevState => ({
                availability: {
                    ...prevState.availability,
                    timeSlots: {
                        ...prevState.availability.timeSlots,
                        [el]: arr
                    }
                }
            }))
        }
    }
    multipleTimeSlot = (el, event) => {
        const index = event.target.getAttribute('data-key');
        const arr = this.state.timeSlots[el.name];
        if (arr === undefined) {
            arr = [];
        }
        arr.push(el);
        this.setState(prevState => ({
            timeSlots: {
                ...prevState.timeSlots,
                [el.name]: arr
            },
            availability: {
                ...prevState.availability,
                error: {}
            }
        }))
    }

    removeSlot = (el, e) => {
        const arrIndex = e.currentTarget.getAttribute('data-index');
        const slot_name = e.currentTarget.getAttribute('data-slot-name');
        const daySlots = this.state.timeSlots[el.name];
        const availabiility = this.state.availability[el.name];
        delete availabiility[slot_name];
        daySlots.splice(arrIndex, 1);
        this.setState(prevState => ({
            timeSlots: {
                ...prevState.timeSlots,
                [el.name]: daySlots
            },
        }))
    }

    slotsTimeOnChange = (event) => {
        const { name, value } = event.target;
        const dayName = event.target.getAttribute('data-key');
        const slotName = event.target.getAttribute('data-slot');
        this.setState(prevState => ({
            availability: {
                ...prevState.availability,
                [dayName]: {
                    ...prevState.availability[dayName],
                    [slotName]: {
                        ...prevState.availability[dayName][slotName],
                        [name]: value
                    }
                },
                error: {}

            }
        }))
    }

    handleSubmit = async (event) => {
        event.preventDefault();
        let arr = {};
        arr['daysDetail'] = {};
        let error = false;
        let errorList = {};
        let days = [
            "Monday",
            "Tuesday",
            "Wednesday",
            "Thursday",
            "Friday",
            "Saturday",
            "Sunday",
        ]
        let errorArr = {};
        days.forEach(day => {
            errorArr[day] = {}

            let a = this.state.availability[day]
            Object.keys(a).forEach((key, index) => {
                if (key) {
                    if (!this.state.availability[day][`slot_${parseFloat(index) + 1}`].start_time) {
                        this.setState(prevState => ({
                            availability: {
                                ...prevState.availability,
                                error: {
                                    ...prevState.availability.error,
                                    [day]: {
                                        ...prevState.availability.error[day],
                                        [`slot_${parseFloat(index) + 1}`]: {
                                            // ...prevState.availability.error[day][`slot_${parseFloat(index)+1}`],
                                            start_time: "This field is required."
                                        }
                                    }
                                }
                            }
                        }))
                        error = true;
                    }
                    if (!this.state.availability[day][`slot_${parseFloat(index) + 1}`].end_time) {
                        this.setState(prevState => ({
                            availability: {
                                ...prevState.availability,
                                error: {
                                    ...prevState.availability.error,
                                    [day]: {
                                        ...prevState.availability.error[day],
                                        [`slot_${parseFloat(index) + 1}`]: {
                                            // ...prevState.availability.error[day][`slot_${parseFloat(index)+1}`],
                                            end_time: "This field is required."
                                        }
                                    }
                                }
                            }
                        }))
                        error = true;
                    }
                }
            });
            arr['daysDetail'][day] = this.state.availability[day]
        });
        if (!this.state.availability.timeZone) {
            this.setState(prevState => ({
                availability: {
                    ...prevState.availability,
                    error: {
                        ...prevState.availability.error,
                        timeZoneError: 'This field is required.'
                    }
                }
            }))
            error = true;
        } else {
            arr['timeZone'] = this.state.availability.timeZone;
        }
        if (error) {
            return
        }
        const response = await ApiRequest.postRequest('/mentorAvailability', arr)
        if (response && response.status === 200) {
            this.tabActiveByClassName('step_three');
        }
    }


